} from "@/lib/validations/auth";

export type SignUpState = {
  error?: string;
};

export async function signUp(
  _prevState: SignUpState,
  formData: FormData,
): Promise<SignUpState> {
  const email = String(formData.get("email") ?? "").trim();
  const password = String(formData.get("password") ?? "");
  const handle = normalizeHandle(String(formData.get("handle") ?? ""));

  if (!validateEmail(email)) {
    return { error: "Enter a valid email address." };
  }

  if (!validatePassword(password)) {
    return { error: "Password must be at least 6 characters." };
  }

  if (!validateHandle(handle)) {
    return {
      error:
        "Handle must be 3-30 characters and use only lowercase letters, numbers, or underscores.",
    };
  }

  const admin = createAdminClient();

  const { data: existingUser } = await admin
    .from("user")
    .select("handle")
    .eq("handle", handle)
    .maybeSingle();

  if (existingUser) {
    return { error: "This handle is already taken." };
  }

  const supabase = await createClient();

  const { data: authData, error: authError } = await supabase.auth.signUp({
    email,
    password,
    options: {
      data: { handle },
    },
  });

  if (authError) {
    return { error: authError.message };
  }

  if (!authData.user) {
    return { error: "Could not create user. Please try again." };
  }

  const { error: profileError } = await admin.from("user").insert({
    id: authData.user.id,
    handle,
    email,
  });

  if (profileError) {
    return { error: profileError.message };
  }

  if (authData.session) {
    redirect("/dashboard");
  }

  redirect("/login");
}

